import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token = json.loads(decoded)
    except (base64.binascii.Error, ValueError):
        return None
    if isinstance(token, dict) and token.get('valid', False):
        return token.get('data')
    return None

from flask import request, Flask, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    data_str = request.args.get('data')
    if not data_str:
        return jsonify(error="No YAML data provided"), 400
    try:
        data = yaml.safe_load(data_str)
    except yaml.YAMLError:
        return jsonify(error="Invalid YAML data"), 400
    return jsonify(data)
